{
  "titulo": "Customer Feedback Form",
  "descripcion": "A form to collect customer feedback and suggestions",
  "preguntas": [
    {
      "id": "q1",
      "tipo": "texto_libre",
      "enunciado": "What is your name?",
      "obligatorio": true,
      "validaciones": {
        "longitud_minima": 2,
        "longitud_maxima": 50
      },
      "posicion": 1
    },
    {
      "id": "q2",
      "tipo": "opcion_multiple",
      "enunciado": "How satisfied are you with our service?",
      "obligatorio": true,
      "opciones": ["Very Satisfied", "Satisfied", "Neutral", "Dissatisfied", "Very Dissatisfied"],
      "posicion": 2
    },
    {
      "id": "q3",
      "tipo": "escala_numerica",
      "enunciado": "Rate our service from 1 to 10",
      "obligatorio": false,
      "validaciones": {
        "valor_minimo": 1,
        "valor_maximo": 10
      },
      "posicion": 3
    },
    {
      "id": "q4",
      "tipo": "checkbox",
      "enunciado": "Which features do you use most?",
      "obligatorio": false,
      "opciones": ["Feature A", "Feature B", "Feature C", "Feature D"],
      "posicion": 4
    }
  ],
  "configuracion": {
    "es_publico": true,
    "usuarios_autorizados": [],
    "requerir_login": false
  }
}

{
  "titulo": "Updated Customer Feedback Form",
  "descripcion": "An updated form to collect customer feedback and suggestions",
  "preguntas": [
    {
      "id": "q1",
      "tipo": "texto_libre",
      "enunciado": "What is your full name?",
      "obligatorio": true,
      "validaciones": {
        "longitud_minima": 3,
        "longitud_maxima": 100
      },
      "posicion": 1
    },
    {
      "id": "q2",
      "tipo": "opcion_multiple",
      "enunciado": "How would you rate our overall service?",
      "obligatorio": true,
      "opciones": ["Excellent", "Good", "Average", "Poor", "Very Poor"],
      "posicion": 2
    }
  ],
  "configuracion": {
    "es_publico": false,
    "usuarios_autorizados": ["{{user_id}}"],
    "requerir_login": true
  }
}

{
  "emails": [
    "user1@example.com",
    "user2@example.com",
    "user3@example.com"
  ],
  "message": "You have been invited to fill out our customer feedback form. Please click the link to participate."
}
